import React from 'react';

export default function Testimonial() {
  return (
    <section style={{
      background: '#fa824c', padding: '108px 52px',
      position: 'relative', overflow: 'hidden',
    }}>

      {/* Large decorative quote marks */}
      <span style={{
        position: 'absolute', top: -40, left: 32,
        fontSize: '22rem', color: 'rgba(255,255,255,.1)',
        fontFamily: 'Georgia, serif', lineHeight: 1,
        pointerEvents: 'none', userSelect: 'none',
      }}>
        "
      </span>
      <span style={{
        position: 'absolute', bottom: -160, right: 32,
        fontSize: '22rem', color: 'rgba(255,255,255,.1)',
        fontFamily: 'Georgia, serif', lineHeight: 1,
        pointerEvents: 'none', userSelect: 'none',
      }}>
        "
      </span>

      <div style={{ maxWidth: 780, margin: '0 auto', textAlign: 'center', position: 'relative' }}>
        <p style={{
          color: 'white', fontSize: 'clamp(1.6rem,3.5vw,2.3rem)',
          fontWeight: 800, lineHeight: 1.52, fontStyle: 'italic', marginBottom: 30,
        }}>
          "I arrived not knowing anyone.<br />
          Global Friends became my family."
        </p>
        <div style={{ display: 'inline-flex', alignItems: 'center', gap: 12 }}>
          <div style={{
            width: 44, height: 44, borderRadius: '50%',
            background: 'rgba(255,255,255,.25)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: '1.4rem',
          }}>
            🇯🇵
          </div>
          <span style={{ color: 'rgba(255,255,255,.9)', fontSize: '1.05rem', fontWeight: 700 }}>
            — Yuki T., from Japan
          </span>
        </div>
      </div>

    </section>
  );
}
